class Solution {
    public String smallestNumber(String pattern) {
        int n = pattern.length();
        int[] nums = new int[n + 1];
        for (int i = 0; i <= n; i++) {
            nums[i] = i;
        }
        for (int i = 0; i < n; i++) {
            if (pattern.charAt(i) == 'D') {
                for (int j = i + 1; j <= n; j++) {
                    if (nums[j] > nums[i]) {
                        int temp = nums[j];
                        nums[j] = nums[i];
                        nums[i] = temp;
                        break;
                    }
                }
            }
        }
        for (int i = 0; i < n; i++) {
            if (pattern.charAt(i) == 'I') {
                for (int j = i + 1; j <= n; j++) {
                    if (nums[j] < nums[i]) {
                        int temp = nums[j];
                        nums[j] = nums[i];
                        nums[i] = temp;
                        break;
                    }
                }
            }
        }
        StringBuilder sb = new StringBuilder();
        for (int num : nums) {
            sb.append(num);
        }
        return sb.toString();
    }
}
